 ****************************/
var mandateName = this.PE_MANDATE_NAME_SL.LABEL;
 var mandateEntitiesOptions = JSON.parse(this._parent.PE_MANDATE_ENTITIES_OPTIONS);
 var filteredMandateEntityOptions = [];
 if (mandateName != undefined && mandateName != null && mandateName != "" && mandateEntitiesOptions != undefined && mandateEntitiesOptions != null && mandateEntitiesOptions != "") {
    filteredMandateEntityOptions = mandateEntitiesOptions[mandateName];
 }
 return filteredMandateEntityOptions;

let value = '';
if (this.PE_MANDATE_ENTITY_OPTIONS_FILTERED.length == 1) {
    value = this.PE_MANDATE_ENTITY_OPTIONS_FILTERED[0].LABEL;
}
return value;
